import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const SYSTEM_PROMPT = `
You are an expert biomechanist, anthropologist, and art historian. 
Your task is to analyze a human body from a photograph to determine proportions, anatomical landmarks, and provide comparative analysis.

You must output strict JSON.

Tasks:
1. Identify the 2D coordinates (0-100 percentage of image width/height) for key anatomical landmarks.
2. Estimate body measurements based on the user's provided height.
3. Provide deep textual analysis on:
    - Population comparison (percentiles).
    - Aesthetic analysis (ideals, symmetry).
    - Artistic comparison (Vitruvian Man, Statue of David).
    - Athletic advantage (biomechanics, levers).
`;

export const analyzeImage = async (
  imageFile: File,
  height: string,
  weight: string,
  heightUnit: string,
  weightUnit: string
): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey });

  // Convert file to base64
  const base64Data = await new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      // Remove data URL prefix (e.g., "data:image/jpeg;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(imageFile);
  });

  const prompt = `
    Analyze this person.
    Height: ${height} ${heightUnit}
    Weight: ${weight} ${weightUnit}

    Identify key landmarks exactly.
    Calculate dimensions in INCHES.

    Return JSON matching this structure:
    {
      "landmarks": {
        "top_skull": {"x": 50, "y": 10},
        "chin": {"x": 50, "y": 15},
        ... (include: l_shoulder, r_shoulder, l_elbow, r_elbow, l_wrist, r_wrist, l_fingertip, r_fingertip, chest_l, chest_r, waist_l, waist_r, hip_l, hip_r, l_knee, r_knee, l_ankle, r_ankle, l_foot, r_foot)
      },
      "measurements": {
        "head_size": "Value in inches",
        "neck_width": "Value in inches",
        "shoulder_width": "Value in inches",
        "arm_length_total": "Value in inches",
        "upper_arm_length": "Value in inches",
        "lower_arm_length": "Value in inches",
        "upper_lower_arm_ratio": "Ratio",
        "wingspan": "Value in inches",
        "hand_length": "Value in inches",
        "chest_width": "Value in inches",
        "torso_length": "Value in inches",
        "hip_width": "Value in inches",
        "chest_waist_ratio": "Ratio",
        "chest_hip_ratio": "Ratio",
        "leg_length_total": "Value in inches",
        "upper_leg_length": "Value in inches",
        "lower_leg_length": "Value in inches",
        "upper_lower_leg_ratio": "Ratio"
      },
      "analysis": {
        "population_comparison": "Markdown string...",
        "aesthetic_beauty": "Markdown string...",
        "artistic_comparison": "Markdown string...",
        "athletic_analysis": "Markdown string..."
      }
    }
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: imageFile.type,
            data: base64Data
          }
        },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      systemInstruction: SYSTEM_PROMPT
    }
  });

  const text = response.text;
  if (!text) {
    throw new Error("No response from AI");
  }

  try {
    return JSON.parse(text) as AnalysisResult;
  } catch (e) {
    console.error("Failed to parse JSON", text);
    throw new Error("Failed to parse analysis results");
  }
};

import React, { useRef, useState } from 'react';
import { Upload, Scale, Ruler, User } from 'lucide-react';
import { UserInput } from '../types';

interface InputFormProps {
  onSubmit: (data: UserInput) => void;
  isLoading: boolean;
}

const InputForm: React.FC<InputFormProps> = ({ onSubmit, isLoading }) => {
  const [height, setHeight] = useState('');
  const [weight, setWeight] = useState('');
  const [heightUnit, setHeightUnit] = useState<'cm' | 'ft'>('ft');
  const [weightUnit, setWeightUnit] = useState<'kg' | 'lbs'>('lbs');
  const [image, setImage] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setImage(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!image || !height || !weight) return;
    onSubmit({ height, weight, heightUnit, weightUnit, image });
  };

  return (
    <div className="w-full max-w-xl mx-auto p-6 bg-zinc-900/50 border border-zinc-800 rounded-2xl shadow-xl backdrop-blur-sm">
      <div className="mb-8 text-center">
        <h2 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-brand-300 to-brand-500 mb-2">
          New Analysis
        </h2>
        <p className="text-zinc-400">
          Upload a full-body photo in "starfish" pose for best results.
        </p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Image Upload Area */}
        <div 
          className={`relative border-2 border-dashed rounded-xl p-8 transition-all duration-300 flex flex-col items-center justify-center cursor-pointer group
            ${preview ? 'border-brand-500/50 bg-zinc-900' : 'border-zinc-700 hover:border-brand-400 hover:bg-zinc-800/50'}`}
          onClick={() => fileInputRef.current?.click()}
        >
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleImageChange} 
            accept="image/*" 
            className="hidden" 
          />

          {preview ? (
            <div className="relative w-full aspect-[3/4] max-h-64 flex justify-center">
              <img src={preview} alt="Preview" className="h-full object-contain rounded-lg shadow-lg" />
              <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center rounded-lg">
                <span className="text-white font-medium bg-zinc-900/80 px-4 py-2 rounded-full backdrop-blur-md">Change Photo</span>
              </div>
            </div>
          ) : (
            <div className="text-center">
              <div className="w-16 h-16 bg-zinc-800 rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform duration-300">
                <Upload className="w-8 h-8 text-brand-400" />
              </div>
              <p className="text-zinc-200 font-medium mb-1">Click to upload photo</p>
              <p className="text-zinc-500 text-sm">JPG, PNG up to 10MB</p>
            </div>
          )}
        </div>

        {/* Measurements Inputs */}
        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-2">
            <label className="flex items-center text-sm font-medium text-zinc-300 gap-2">
              <Ruler className="w-4 h-4 text-brand-400" /> Height
            </label>
            <div className="relative">
              <input
                type="number"
                value={height}
                onChange={(e) => setHeight(e.target.value)}
                placeholder={heightUnit === 'ft' ? "5.9" : "175"}
                className="w-full bg-zinc-950 border border-zinc-800 rounded-lg py-3 px-4 text-zinc-100 focus:outline-none focus:ring-2 focus:ring-brand-500/50 focus:border-brand-500 transition-all"
                required
              />
              <select
                value={heightUnit}
                onChange={(e) => setHeightUnit(e.target.value as 'cm' | 'ft')}
                className="absolute right-2 top-2 bg-zinc-800 border-none text-zinc-300 text-sm rounded-md py-1 px-2 cursor-pointer hover:bg-zinc-700"
              >
                <option value="ft">ft</option>
                <option value="cm">cm</option>
              </select>
            </div>
          </div>

          <div className="space-y-2">
            <label className="flex items-center text-sm font-medium text-zinc-300 gap-2">
              <Scale className="w-4 h-4 text-brand-400" /> Weight
            </label>
            <div className="relative">
              <input
                type="number"
                value={weight}
                onChange={(e) => setWeight(e.target.value)}
                placeholder={weightUnit === 'lbs' ? "160" : "75"}
                className="w-full bg-zinc-950 border border-zinc-800 rounded-lg py-3 px-4 text-zinc-100 focus:outline-none focus:ring-2 focus:ring-brand-500/50 focus:border-brand-500 transition-all"
                required
              />
              <select
                value={weightUnit}
                onChange={(e) => setWeightUnit(e.target.value as 'kg' | 'lbs')}
                className="absolute right-2 top-2 bg-zinc-800 border-none text-zinc-300 text-sm rounded-md py-1 px-2 cursor-pointer hover:bg-zinc-700"
              >
                <option value="lbs">lbs</option>
                <option value="kg">kg</option>
              </select>
            </div>
          </div>
        </div>

        <button
          type="submit"
          disabled={isLoading || !image}
          className={`w-full py-4 rounded-xl font-bold text-lg shadow-lg flex items-center justify-center gap-2 transition-all duration-300
