import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const SYSTEM_PROMPT = `
You are an expert biomechanist, anthropologist, and art historian. 
Your task is to analyze a human body from a photograph to determine proportions, anatomical landmarks, and provide comparative analysis.

You must output strict JSON.

Tasks:
1. Identify the 2D coordinates (0-100 percentage of image width/height) for key anatomical landmarks. 
   CRITICAL: Be extremely precise. Locate the CENTER of rotation for joints (knees, elbows, shoulders, hips) and the exact tips for extremities.
2. Estimate body measurements based on the user's provided height.
3. Provide deep textual analysis on:
    - Population comparison (percentiles).
    - Aesthetic analysis (ideals, symmetry).
    - Artistic comparison (Vitruvian Man, Statue of David).
    - Athletic advantage (biomechanics, levers).
    - Sport-specific analysis (if a sport is provided, identifying best positions).
`;

export const analyzeImage = async (
  imageFile: File,
  height: string,
  weight: string,
  heightUnit: string,
  weightUnit: string,
  sport?: string
): Promise<AnalysisResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey });

  // Convert file to base64
  const base64Data = await new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      // Remove data URL prefix (e.g., "data:image/jpeg;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(imageFile);
  });

  const sportPrompt = sport 
    ? `
      DETAILED SPORT ANALYSIS REQUIRED for: "${sport}".

      You must provide a breakdown of how this body type fits into specific positions or movements within this sport.

      Examples:
      - If "American Football": Analyze suitability for Lineman vs Running Back vs Receiver vs Quarterback based on limb length, torso size, and center of mass.
      - If "Powerlifting": Analyze mechanical advantages/disadvantages for the Squat, Bench Press, and Deadlift separately (e.g., "Long femurs may make squatting harder but short arms help bench press").
      - If "Swimming": Analyze drag and propulsion potential based on torso shape and wingspan.

      Be specific about the BIOMECHANICAL reasons (leverage, torque, range of motion) why they fit or do not fit specific roles.
      `
    : "";

  const prompt = `
    Analyze this person.
    Height: ${height} ${heightUnit}
    Weight: ${weight} ${weightUnit}
    ${sportPrompt}

    Identify key landmarks exactly.
    Calculate dimensions in INCHES.

    Return JSON matching this structure:
    {
      "landmarks": {
        "top_skull": {"x": 50, "y": 10},
        "chin": {"x": 50, "y": 15},
        ... (include: l_shoulder, r_shoulder, l_elbow, r_elbow, l_wrist, r_wrist, l_fingertip, r_fingertip, chest_l, chest_r, waist_l, waist_r, hip_l, hip_r, l_knee, r_knee, l_ankle, r_ankle, l_foot, r_foot)
      },
      "measurements": {
        "head_size": "Value in inches",
        "neck_width": "Value in inches",
        "shoulder_width": "Value in inches",
        "arm_length_total": "Value in inches",
        "upper_arm_length": "Value in inches",
        "lower_arm_length": "Value in inches",
        "upper_lower_arm_ratio": "Ratio",
        "wingspan": "Value in inches",
        "hand_length": "Value in inches",
        "chest_width": "Value in inches",
        "torso_length": "Value in inches",
        "hip_width": "Value in inches",
        "chest_waist_ratio": "Ratio",
        "chest_hip_ratio": "Ratio",
        "leg_length_total": "Value in inches",
        "upper_leg_length": "Value in inches",
        "lower_leg_length": "Value in inches",
        "upper_lower_leg_ratio": "Ratio"
      },
      "analysis": {
        "population_comparison": "Markdown string...",
        "aesthetic_beauty": "Markdown string...",
        "artistic_comparison": "Markdown string...",
        "athletic_analysis": "Markdown string...",
        "sport_specific_analysis": "Markdown string (Required if sport is provided)..."
      }
    }
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: imageFile.type,
            data: base64Data
          }
        },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      systemInstruction: SYSTEM_PROMPT
    }
  });

  const text = response.text;
  if (!text) {
    throw new Error("No response from AI");
  }

  try {
    return JSON.parse(text) as AnalysisResult;
  } catch (e) {
    console.error("Failed to parse JSON", text);
    throw new Error("Failed to parse analysis results");
  }
};

import React from 'react';
import { BodyLandmarks, BodyMeasurements, Coordinates } from '../types';

interface BodyDiagramProps {
  imageSrc: string;
  landmarks: BodyLandmarks;
  measurements?: BodyMeasurements;
}

const BodyDiagram: React.FC<BodyDiagramProps> = ({ imageSrc, landmarks, measurements }) => {
  // Helper to convert % to standard CSS string
  const toPos = (coord: Coordinates) => ({
    left: `${coord.x}%`,
    top: `${coord.y}%`
  });

  const Point = ({ coord, label }: { coord: Coordinates; label?: string }) => {
    if (!coord) return null;
    return (
      <div
        className="absolute w-2 h-2 -ml-1 -mt-1 bg-brand-300 rounded-full shadow-[0_0_8px_rgba(45,212,191,0.8)] z-10 group"
        style={toPos(coord)}
      >
        {label && (
          <div className="absolute left-3 top-0 bg-black/80 text-[10px] text-brand-100 px-1.5 py-0.5 rounded opacity-0 group-hover:opacity-100 whitespace-nowrap pointer-events-none transition-opacity z-20">
            {label}
          </div>
        )}
      </div>
    );
  };

  // Construct an SVG path string for connections
  const Line = ({ p1, p2 }: { p1: Coordinates, p2: Coordinates }) => {
     if(!p1 || !p2) return null;
     return <line x1={`${p1.x}%`} y1={`${p1.y}%`} x2={`${p2.x}%`} y2={`${p2.y}%`} stroke="#2dd4bf" strokeWidth="1.5" strokeOpacity="0.6" />;
  }

  // Label for dimensions (e.g. "14 in") placed at the midpoint of a line
  const DimensionLabel = ({ p1, p2, value, offsetX = 0, offsetY = 0 }: { p1: Coordinates, p2: Coordinates, value?: string, offsetX?: number, offsetY?: number }) => {
    if (!p1 || !p2 || !value) return null;

    const midX = (p1.x + p2.x) / 2;
    const midY = (p1.y + p2.y) / 2;

    return (
      <div 
        className="absolute transform -translate-x-1/2 -translate-y-1/2 z-10"
        style={{ left: `${midX + offsetX}%`, top: `${midY + offsetY}%` }}
      >
        <span className="bg-black/60 backdrop-blur-[2px] text-[10px] md:text-xs text-brand-100 px-1.5 py-0.5 rounded border border-brand-500/20 whitespace-nowrap">
          {value}
        </span>
      </div>
    );
  };

  return (
    <div className="relative w-full h-full bg-black rounded-xl overflow-hidden shadow-2xl border border-zinc-800 group/container">
      {/* Background Image */}
      <img
        src={imageSrc}
        alt="Analyzed Body"
        className="w-full h-full object-contain object-center opacity-40 grayscale contrast-125 transition-all duration-500 group-hover/container:opacity-60"
      />

      {/* Grid Overlay for "Scanner" effect */}
      <div className="absolute inset-0 bg-[linear-gradient(rgba(45,212,191,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(45,212,191,0.03)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>

      {/* SVG Layer for Connecting Lines */}
      <svg className="absolute inset-0 w-full h-full pointer-events-none z-0">
        <Line p1={landmarks.top_skull} p2={landmarks.chin} />
        <Line p1={landmarks.chin} p2={landmarks.l_shoulder} />
        <Line p1={landmarks.chin} p2={landmarks.r_shoulder} />

        {/* Arms */}
        <Line p1={landmarks.l_shoulder} p2={landmarks.l_elbow} />
        <Line p1={landmarks.l_elbow} p2={landmarks.l_wrist} />
        <Line p1={landmarks.l_wrist} p2={landmarks.l_fingertip} />

        <Line p1={landmarks.r_shoulder} p2={landmarks.r_elbow} />
        <Line p1={landmarks.r_elbow} p2={landmarks.r_wrist} />
        <Line p1={landmarks.r_wrist} p2={landmarks.r_fingertip} />

        {/* Torso */}
        <Line p1={landmarks.l_shoulder} p2={landmarks.waist_l} />
        <Line p1={landmarks.r_shoulder} p2={landmarks.waist_r} />
        <Line p1={landmarks.waist_l} p2={landmarks.hip_l} />
        <Line p1={landmarks.waist_r} p2={landmarks.hip_r} />
        <Line p1={landmarks.hip_l} p2={landmarks.hip_r} />
        <Line p1={landmarks.l_shoulder} p2={landmarks.r_shoulder} />

        {/* Legs */}
        <Line p1={landmarks.hip_l} p2={landmarks.l_knee} />
        <Line p1={landmarks.l_knee} p2={landmarks.l_ankle} />
        <Line p1={landmarks.l_ankle} p2={landmarks.l_foot} />

        <Line p1={landmarks.hip_r} p2={landmarks.r_knee} />
        <Line p1={landmarks.r_knee} p2={landmarks.r_ankle} />
        <Line p1={landmarks.r_ankle} p2={landmarks.r_foot} />
      </svg>

      {/* Dimension Labels (Overlay) */}
      {measurements && (
        <>
          {/* Right Arm (User's Left) */}
          <DimensionLabel p1={landmarks.l_shoulder} p2={landmarks.l_elbow} value={measurements.upper_arm_length} offsetX={-2} />
          <DimensionLabel p1={landmarks.l_elbow} p2={landmarks.l_wrist} value={measurements.lower_arm_length} offsetX={-2} />

          {/* Right Leg (User's Left) */}
          <DimensionLabel p1={landmarks.hip_l} p2={landmarks.l_knee} value={measurements.upper_leg_length} offsetX={-2} />
          <DimensionLabel p1={landmarks.l_knee} p2={landmarks.l_ankle} value={measurements.lower_leg_length} offsetX={-2} />

          {/* Torso/Shoulders */}
          <DimensionLabel p1={landmarks.l_shoulder} p2={landmarks.r_shoulder} value={measurements.shoulder_width} offsetY={-3} />
          <DimensionLabel p1={landmarks.hip_l} p2={landmarks.hip_r} value={measurements.hip_width} offsetY={3} />

          {/* Wingspan (Approximate label placement) */}
          {/* We'll just show it near the head since it spans the whole body width */}
          <div className="absolute top-[5%] left-1/2 transform -translate-x-1/2">
             <span className="bg-brand-900/80 text-brand-200 text-xs px-2 py-1 rounded border border-brand-500/30">
               Wingspan: {measurements.wingspan}
             </span>
          </div>
        </>
      )}

      {/* Points Layer */}
      <Point coord={landmarks.top_skull} label="Top Skull" />
      <Point coord={landmarks.chin} label="Chin" />
      <Point coord={landmarks.l_shoulder} label="L Shoulder" />
      <Point coord={landmarks.r_shoulder} label="R Shoulder" />
      <Point coord={landmarks.l_elbow} label="L Elbow" />
      <Point coord={landmarks.r_elbow} label="R Elbow" />
      <Point coord={landmarks.l_wrist} label="L Wrist" />
      <Point coord={landmarks.r_wrist} label="R Wrist" />
      <Point coord={landmarks.l_fingertip} label="L Finger" />
      <Point coord={landmarks.r_fingertip} label="R Finger" />
      <Point coord={landmarks.hip_l} label="L Hip" />
      <Point coord={landmarks.hip_r} label="R Hip" />
      <Point coord={landmarks.l_knee} label="L Knee" />
      <Point coord={landmarks.r_knee} label="R Knee" />
      <Point coord={landmarks.l_ankle} label="L Ankle" />
      <Point coord={landmarks.r_ankle} label="R Ankle" />
    </div>
  );
};

