import React, { useState } from 'react';
import InputForm from './components/InputForm';
import BodyDiagram from './components/BodyDiagram';
import AnalysisResults from './components/AnalysisResults';
import { UserInput, AnalysisResult } from './types';
import { analyzeImage } from './services/gemini';
import { ScanFace, ChevronLeft } from 'lucide-react';

const App: React.FC = () => {
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [currentImage, setCurrentImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleInputSubmit = async (input: UserInput) => {
    setIsLoading(true);
    setError(null);
    try {
      // Create a local URL for the image to display immediately
      const imageUrl = URL.createObjectURL(input.image!);
      setCurrentImage(imageUrl);

      const result = await analyzeImage(
        input.image!, 
        input.height, 
        input.weight, 
        input.heightUnit, 
        input.weightUnit,
        input.sex,
        input.age,
        input.sport
      );
      setData(result);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "An error occurred during analysis.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleReset = () => {
    setData(null);
    setCurrentImage(null);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-black text-white selection:bg-brand-500/30">
      {/* Header */}
      <header className="fixed top-0 left-0 right-0 z-50 border-b border-zinc-800 bg-black/80 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-brand-500/10 p-2 rounded-lg">
              <ScanFace className="w-6 h-6 text-brand-400" />
            </div>
            <h1 className="text-xl font-bold tracking-tight text-transparent bg-clip-text bg-gradient-to-r from-brand-100 to-brand-400">
              VITRUVIAN<span className="font-light text-brand-600">.AI</span>
            </h1>
          </div>
          {data && (
            <button 
              onClick={handleReset}
              className="text-sm font-medium text-zinc-400 hover:text-white flex items-center gap-1 transition-colors"
            >
              <ChevronLeft className="w-4 h-4" /> New Scan
            </button>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="pt-24 pb-12 px-4 max-w-7xl mx-auto min-h-screen">
        {!data && !isLoading && !currentImage && (
          <div className="flex flex-col items-center justify-center min-h-[70vh] animate-in fade-in zoom-in duration-500">
             <div className="text-center mb-12 max-w-2xl">
                <h2 className="text-4xl md:text-5xl font-bold mb-6 leading-tight">
                  Unlock your <span className="text-brand-400">Biological Blueprint</span>
                </h2>
                <p className="text-lg text-zinc-400">
                  Advanced AI biomechanical analysis comparing your proportions to classical ideals, athletic standards, and population datasets.
                </p>
             </div>
             <InputForm onSubmit={handleInputSubmit} isLoading={isLoading} />
          </div>
        )}

        {(isLoading || (currentImage && !data)) && (
          <div className="flex flex-col items-center justify-center min-h-[70vh]">
            <div className="relative w-32 h-32 mb-8">
              <div className="absolute inset-0 border-4 border-zinc-800 rounded-full"></div>
              <div className="absolute inset-0 border-4 border-brand-500 border-t-transparent rounded-full animate-spin"></div>
              <ScanFace className="absolute inset-0 m-auto w-12 h-12 text-brand-500 animate-pulse" />
            </div>
            <h3 className="text-2xl font-bold text-white mb-2">Analyzing Anatomy</h3>
            <p className="text-zinc-500 animate-pulse">Calculating levers, ratios, and comparisons...</p>
          </div>
        )}

        {error && (
          <div className="max-w-xl mx-auto mt-12 p-6 bg-red-950/20 border border-red-900/50 rounded-xl text-center">
            <h3 className="text-red-400 font-bold text-lg mb-2">Analysis Failed</h3>
            <p className="text-red-200/70 mb-4">{error}</p>
            <button 
              onClick={handleReset}
              className="px-6 py-2 bg-red-900/30 hover:bg-red-900/50 text-red-200 rounded-lg transition-colors"
            >
              Try Again
            </button>
          </div>
        )}

        {data && currentImage && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-8rem)]">
             {/* Left Column: Interactive Diagram */}
             <div className="lg:col-span-5 h-[50vh] lg:h-full relative flex flex-col">
               <div className="flex-1 bg-zinc-900/30 rounded-2xl border border-zinc-800 p-2 relative">
                 <BodyDiagram 
                    imageSrc={currentImage} 
                    landmarks={data.landmarks}
                    measurements={data.measurements} 
                  />
               </div>
               <div className="mt-4 text-center">
                 <p className="text-xs text-zinc-500 font-mono">
                   * Diagram coordinates are AI-estimated overlays
                 </p>
               </div>
             </div>

             {/* Right Column: Analysis Data */}
             <div className="lg:col-span-7 h-full bg-zinc-950/50 rounded-2xl border border-zinc-800/50 p-6 lg:overflow-hidden flex flex-col">
                <AnalysisResults data={data} />
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { Upload, Scale, Ruler, User, Trophy, CheckCircle2, Circle, Users, Calendar } from 'lucide-react';
import { UserInput } from '../types';

interface InputFormProps {
  onSubmit: (data: UserInput) => void;
  isLoading: boolean;
}

const SPORTS = [
  "American Football", "Archery", "Auto Racing", "Badminton", "Baseball", 
  "Basketball", "Billiards/Pool", "Bodybuilding", "Bowling", "Boxing", 
  "Cheerleading", "Cricket", "CrossFit", "Cycling", "Dance", 
  "Equestrian/Horse Racing", "Fencing", "Field Hockey", "Fishing", "Golf", 
  "Gymnastics", "Handball", "Hiking/Mountaineering", "Hunting", "Ice Hockey", 
  "Lacrosse", "MMA", "Pickleball", "Powerlifting", "Racquetball", 
  "Rock Climbing", "Rodeo", "Rowing", "Rugby", "Running (Distance)", 
  "Running (Sprinting)", "Shooting", "Skateboarding", "Skiing", "Snowboarding", 
  "Soccer", "Softball", "Surfing", "Swimming", "Table Tennis", 
  "Tennis", "Track & Field (Field Events)", "Triathlon", "Ultimate Frisbee", 
  "Volleyball", "Water Polo", "Wrestling", "Yoga"
];

const InputForm: React.FC<InputFormProps> = ({ onSubmit, isLoading }) => {
  const [sex, setSex] = useState<'Male' | 'Female' | 'Other' | ''>('');
  const [age, setAge] = useState('');
  const [heightCm, setHeightCm] = useState('');
  const [heightFt, setHeightFt] = useState('');
  const [heightIn, setHeightIn] = useState('');
  const [weight, setWeight] = useState('');
  const [heightUnit, setHeightUnit] = useState<'cm' | 'ft'>('ft');
  const [weightUnit, setWeightUnit] = useState<'kg' | 'lbs'>('lbs');
  const [image, setImage] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [enableSport, setEnableSport] = useState(false);
  const [sport, setSport] = useState('');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setImage(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setPreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const isSexValid = sex !== '';
  const isAgeValid = age !== '';
  const isHeightValid = heightUnit === 'ft' ? (heightFt !== '' && heightIn !== '') : (heightCm !== '');
  const isWeightValid = weight !== '';
  const isImageValid = image !== null;
  const isFormValid = isSexValid && isAgeValid && isHeightValid && isWeightValid && isImageValid;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isFormValid || sex === '') return;

    let finalHeight = heightCm;
    if (heightUnit === 'ft') {
      finalHeight = `${heightFt}'${heightIn}`;
    }

    onSubmit({ 
      sex: sex as 'Male' | 'Female' | 'Other',
      age,
      height: finalHeight, 
      weight, 
      heightUnit, 
      weightUnit, 
      image,
      sport: enableSport ? sport : undefined
    });
  };

  const StepIndicator = ({ label, valid }: { label: string, valid: boolean }) => (
    <div className={`flex items-center gap-2 text-sm font-medium transition-colors ${valid ? 'text-brand-400' : 'text-zinc-600'}`}>
      {valid ? <CheckCircle2 className="w-5 h-5" /> : <Circle className="w-5 h-5" />}
      {label}
    </div>
  );

  return (
    <div className="w-full max-w-xl mx-auto p-6 bg-zinc-900/50 border border-zinc-800 rounded-2xl shadow-xl backdrop-blur-sm">
      <div className="mb-6 text-center">
        <h2 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-brand-300 to-brand-500 mb-2">
          New Analysis
        </h2>
        <p className="text-zinc-400 mb-6">
          Upload a full-body photo in "starfish" pose for best results.
        </p>

        {/* Visual Progress/Validation */}
        <div className="flex justify-center gap-4 md:gap-6 p-4 bg-zinc-950/50 rounded-lg border border-zinc-800/50 flex-wrap">
          <StepIndicator label="Sex" valid={isSexValid} />
          <StepIndicator label="Age" valid={isAgeValid} />
          <StepIndicator label="Photo" valid={isImageValid} />
          <StepIndicator label="Height" valid={isHeightValid} />
          <StepIndicator label="Weight" valid={isWeightValid} />
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Sex Selection */}
        <div className="grid grid-cols-3 gap-3">
          {(['Male', 'Female', 'Other'] as const).map((option) => (
            <button
              key={option}
              type="button"
              onClick={() => setSex(option)}
              className={`py-3 px-4 rounded-lg font-medium text-sm transition-all flex items-center justify-center gap-2
                ${sex === option 
                  ? 'bg-brand-600 text-white shadow-lg shadow-brand-500/20 border-transparent' 
                  : 'bg-zinc-950 border border-zinc-800 text-zinc-400 hover:border-zinc-600 hover:text-zinc-200'}`}
            >
              <Users className="w-4 h-4" />
              {option}
            </button>
          ))}
        </div>

        {/* Image Upload Area */}
        <div 
          className={`relative border-2 border-dashed rounded-xl p-8 transition-all duration-300 flex flex-col items-center justify-center cursor-pointer group
            ${preview ? 'border-brand-500/50 bg-zinc-900' : 'border-zinc-700 hover:border-brand-400 hover:bg-zinc-800/50'}`}
          onClick={() => fileInputRef.current?.click()}
        >
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleImageChange} 
            accept="image/*" 
            className="hidden" 
          />

          {preview ? (
            <div className="relative w-full aspect-[3/4] max-h-64 flex justify-center">
              <img src={preview} alt="Preview" className="h-full object-contain rounded-lg shadow-lg" />
              <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center rounded-lg">
                <span className="text-white font-medium bg-zinc-900/80 px-4 py-2 rounded-full backdrop-blur-md">Change Photo</span>
              </div>
            </div>
          ) : (
            <div className="text-center">
              <div className="w-16 h-16 bg-zinc-800 rounded-full flex items-center justify-center mx-auto mb-4 group-hover:scale-110 transition-transform duration-300">
                <Upload className="w-8 h-8 text-brand-400" />
              </div>
              <p className="text-zinc-200 font-medium mb-1">Click to upload photo</p>
              <p className="text-zinc-500 text-sm">JPG, PNG up to 10MB</p>
            </div>
          )}
        </div>

        {/* Measurements Inputs (Age, Weight, Height) */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {/* Age Input */}
          <div className="space-y-2">
            <label className="flex items-center text-sm font-medium text-zinc-300 gap-2">
              <Calendar className="w-4 h-4 text-brand-400" /> Age
            </label>
            <input
              type="number"
              value={age}
              onChange={(e) => setAge(e.target.value)}
              placeholder="25"
              className="w-full bg-zinc-950 border border-zinc-800 rounded-lg py-3 px-4 text-zinc-100 focus:outline-none focus:ring-2 focus:ring-brand-500/50 focus:border-brand-500 transition-all text-center"
              required
              min="1"
              max="120"
            />
          </div>

          {/* Weight Input */}
          <div className="space-y-2">
            <label className="flex items-center text-sm font-medium text-zinc-300 gap-2">
              <Scale className="w-4 h-4 text-brand-400" /> Weight
            </label>
            <div className="relative flex gap-2">
              <div className="relative w-full">
                <input
                  type="number"
                  value={weight}
                  onChange={(e) => setWeight(e.target.value)}
                  placeholder={weightUnit === 'lbs' ? "160" : "75"}
                  className="w-full bg-zinc-950 border border-zinc-800 rounded-lg py-3 px-4 text-zinc-100 focus:outline-none focus:ring-2 focus:ring-brand-500/50 focus:border-brand-500 transition-all text-center"
                  required
                />
              </div>
              <select
                value={weightUnit}
                onChange={(e) => setWeightUnit(e.target.value as 'kg' | 'lbs')}
                className="bg-zinc-800 border border-zinc-700 text-zinc-300 text-sm rounded-lg px-2 cursor-pointer hover:bg-zinc-700 focus:outline-none"
              >
                <option value="lbs">lbs</option>
                <option value="kg">kg</option>
              </select>
            </div>
          </div>

          {/* Height Input (Full Width) */}
          <div className="space-y-2 md:col-span-2">
            <label className="flex items-center text-sm font-medium text-zinc-300 gap-2">
              <Ruler className="w-4 h-4 text-brand-400" /> Height
            </label>
            <div className="flex gap-2">
              {heightUnit === 'ft' ? (
                <>
                  <div className="relative flex-1">
                    <input
                      type="number"
                      value={heightFt}
                      onChange={(e) => setHeightFt(e.target.value)}
                      placeholder="5"
