          <div className="absolute left-3 top-0 bg-black/80 text-[10px] text-brand-100 px-1.5 py-0.5 rounded opacity-0 group-hover:opacity-100 whitespace-nowrap pointer-events-none transition-opacity z-20">
            {label}
